import concurrent.futures, json

def run_tools_parallel(tool_calls: list, registry: dict) -> list:
    results = []
    with concurrent.futures.ThreadPoolExecutor() as ex:
        futures = {
            ex.submit(registry[tc.name], **tc.input): tc
            for tc in tool_calls if tc.name in registry
        }
        for future, tc in futures.items():
            try:
                result = future.result(timeout=30)
            except Exception as e:
                result = {"error": str(e), "code": "TOOL_ERROR"}
            results.append({
                "type": "tool_result",
                "tool_use_id": tc.id,
                "content": json.dumps(result)[:8000]  # truncate to ~2000 tokens
            })
    return results

import json, anthropic

client = anthropic.Anthropic()

def agent_loop(tools: list, registry: dict, messages: list,
               max_iterations: int = 10) -> str:
    for i in range(max_iterations):
        resp = client.messages.create(
            model="claude-sonnet-4-20250514",
            max_tokens=4096,
            tools=tools,
            messages=messages
        )
        if resp.stop_reason == "end_turn":
            return resp.content[0].text
        if resp.stop_reason == "max_tokens":
            raise ValueError("Response truncated; increase max_tokens")
        # Handle tool_use
        messages.append({"role": "assistant", "content": resp.content})
        tool_results = []
        for block in resp.content:
            if block.type == "tool_use":
                try:
                    result = registry[block.name](**block.input)
                except Exception as e:
                    result = {"error": str(e), "code": "TOOL_ERROR"}
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": json.dumps(result)
                })
        messages.append({"role": "user", "content": tool_results})
    raise RuntimeError(f"max_iterations={max_iterations} reached")
